mapper.select:
SELECT result.time, ROUND(SUM(result.nvmActivePower), 1) AS value FROM (
SELECT d.id, FROM_UNIXTIME(( UNIX_TIMESTAMP( CONVERT_TZ( tbl.time, 'UTC', t.value ) ) DIV 900 )* 900, '%Y-%m-%d %H:%i' ) AS time, sub.nvmActivePower FROM ${meter.datatablename} tbl JOIN device d ON d.id = tbl.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT sub_tbl.id_device, MIN(sub_tbl.time) AS minTime, AVG(sub_tbl.nvmActivePower) AS nvmActivePower FROM ${meter.datatablename} sub_tbl JOIN device sub_d ON sub_d.id = sub_tbl.id_device JOIN site sub_s ON sub_s.id = sub_d.id_site JOIN time_zone sub_t ON sub_t.id = sub_s.id_time_zone WHERE sub_s.id = #{request.siteId} AND sub_s.`status` = 1 AND sub_d.id = #{meter.deviceId} AND sub_d.`status` = 1 AND sub_tbl.time BETWEEN CONVERT_TZ(#{request.startDate}, sub_t.value, 'UTC') AND CONVERT_TZ(#{request.endDate}, sub_t.value, 'UTC') AND sub_tbl.nvmActiveEnergy IS NOT NULL GROUP BY sub_tbl.id_device, FROM_UNIXTIME(( UNIX_TIMESTAMP( CONVERT_TZ( sub_tbl.time, 'UTC', sub_t.value ) ) DIV 900 )* 900, '%Y-%m-%d %H:%i' ) ) sub ON sub.minTime = tbl.time AND sub.id_device = tbl.id_device
) result GROUP BY result.time ORDER BY result.time
